WHERE code = '1381';

UPDATE products SET 
  descriptionEn = 'Abrasion resistant composite material for the repair and lining of metal surfaces subject to erosive attack. Belzona 1811 (Ceramic Carbide) combines ceramic carbide particles with epoxy resin to create an extremely hard, wear-resistant composite. It provides outstanding protection against particle erosion, cavitation, and abrasive wear. The material can be applied as a putty or paste and shaped to match equipment contours. It cures to a hard composite that significantly extends equipment life. Typical applications include pump impellers, fan blades, turbine components, and other equipment suffering from high-velocity particle erosion.',
  descriptionEl = 'Σύνθετο υλικό ανθεκτικό στην τριβή για επιδιόρθωση και επένδυση μεταλλικών επιφανειών που υπόκεινται σε διαβρωτική επίθεση. Το Belzona 1811 (Ceramic Carbide) συνδυάζει σωματίδια κεραμικού καρβιδίου με εποξειδική ρητίνη για δημιουργία εξαιρετικά σκληρού, ανθεκτικού σύνθετου.'
WHERE code = '1811';

