UPDATE products SET 
  descriptionEn = 'An epoxy coating for corrosion and chemical protection of high temperature equipment operating under immersion. Belzona 5892 combines high temperature performance with excellent corrosion and chemical resistance. It maintains protective properties at elevated temperatures and in aggressive aqueous environments. The coating offers superior adhesion to steel and other metal substrates and cures to a hard, protective finish. Ideal for protecting high temperature immersion equipment in chemical plants, power generation facilities, and other industrial environments.',
  descriptionEl = 'Επίστρωση εποξειδικής ρητίνης για προστασία από διάβρωση και χημική προστασία εξοπλισμού υψηλής θερμοκρασίας που λειτουργεί υπό βύθιση. Το Belzona 5892 συνδυάζει απόδοση υψηλής θερμοκρασίας με εξαιρετική αντίσταση στη διάβρωση και χημική αντίσταση.'
WHERE code = '5892';

-- Update remaining products with brief descriptions for now
UPDATE products SET 
  descriptionEn = 'Environmental corrosion protection epoxy coating for metallic surfaces. Provides long-term protection against corrosion in diverse industrial environments.',
  descriptionEl = 'Επίστρωση εποξειδικής ρητίνης για προστασία περιβάλλοντος από διάβρωση μεταλλικών επιφανειών. Παρέχει μακροχρόνια προστασία κατά της διάβρωσης.'
WHERE code IN ('6111', '7111', '7211', '7311', '8211', '8311', '9611', '9631');
